import{c as d,cG as t,cb as e,c8 as o,cf as r,cT as c,ce as l}from"./chunks/framework.BlkIsu1j.js";const a=JSON.parse('{"title":"附录 C. 伪指令速查表","description":"","frontmatter":{"title":"附录 C. 伪指令速查表","outline":"deep","layout":"doc","prev":{"text":"附录 B. 标准扩展指令速查表","link":"/lang/assembly/appendix_b_extensions_reference"},"next":{"text":"附录 D. 寄存器 ABI 速查表","link":"/lang/assembly/appendix_d_register_abi"},"sidebar":true,"date":"2026-05-31T10:00:00.000Z"},"headers":[],"relativePath":"lang/assembly/appendix_c_pseudo_instructions.md","filePath":"lang/assembly/appendix_c_pseudo_instructions.md","lastUpdated":1780203693000}'),s={id:"frontmatter-title",tabindex:"-1"};const b=d({name:"lang/assembly/appendix_c_pseudo_instructions.md"},[["render",function(d,a,b,h,i,n){return t(),e("div",null,[o("h1",s,[r(c(d.$frontmatter.title)+" ",1),a[0]||(a[0]=o("a",{class:"header-anchor",href:"#frontmatter-title","aria-label":"Permalink to “{{ $frontmatter.title }}”"},"​",-1))]),a[1]||(a[1]=l('<p>伪指令（pseudo-instructions）是汇编器提供的语法糖，在汇编时被&quot;展开&quot;为一条或多条真实 RISC-V 指令。理解伪指令的展开规则，有助于阅读反汇编输出和精准控制生成的机器码。以下按功能类别列出 RISC-V 标准伪指令全集。</p><hr><h2 id="寄存器间移动" tabindex="-1">寄存器间移动 <a class="header-anchor" href="#寄存器间移动" aria-label="Permalink to “寄存器间移动”">​</a></h2><table tabindex="0"><thead><tr><th>伪指令</th><th>语法</th><th>展开为</th><th>说明</th></tr></thead><tbody><tr><td><code>mv</code></td><td><code>mv rd, rs</code></td><td><code>addi rd, rs, 0</code></td><td>rd = rs</td></tr><tr><td><code>not</code></td><td><code>not rd, rs</code></td><td><code>xori rd, rs, -1</code></td><td>rd = ~rs（按位取反）</td></tr><tr><td><code>neg</code></td><td><code>neg rd, rs</code></td><td><code>sub rd, x0, rs</code></td><td>rd = -rs（算术取负）</td></tr><tr><td><code>negw</code></td><td><code>negw rd, rs</code></td><td><code>subw rd, x0, rs</code></td><td>rd = sign_extend(-rs[31:0])（RV64）</td></tr><tr><td><code>sext.w</code></td><td><code>sext.w rd, rs</code></td><td><code>addiw rd, rs, 0</code></td><td>rd = sign_extend(rs[31:0])（RV64）</td></tr><tr><td><code>seqz</code></td><td><code>seqz rd, rs</code></td><td><code>sltiu rd, rs, 1</code></td><td>rd = (rs == 0) ? 1 : 0</td></tr><tr><td><code>snez</code></td><td><code>snez rd, rs</code></td><td><code>sltu rd, x0, rs</code></td><td>rd = (rs != 0) ? 1 : 0</td></tr><tr><td><code>sltz</code></td><td><code>sltz rd, rs</code></td><td><code>slt rd, rs, x0</code></td><td>rd = (rs &lt; 0) ? 1 : 0</td></tr><tr><td><code>sgtz</code></td><td><code>sgtz rd, rs</code></td><td><code>slt rd, x0, rs</code></td><td>rd = (rs &gt; 0) ? 1 : 0</td></tr></tbody></table><hr><h2 id="立即数加载" tabindex="-1">立即数加载 <a class="header-anchor" href="#立即数加载" aria-label="Permalink to “立即数加载”">​</a></h2><table tabindex="0"><thead><tr><th>伪指令</th><th>语法</th><th>展开为</th><th>说明</th></tr></thead><tbody><tr><td><code>li</code></td><td><code>li rd, imm</code></td><td>由汇编器自动选择最优序列</td><td>加载 64 位有符号立即数</td></tr><tr><td><code>li</code></td><td><code>li rd, imm</code>（-2048 &lt;= imm &lt; 2048）</td><td><code>addi rd, x0, imm</code></td><td>小立即数</td></tr><tr><td><code>li</code></td><td><code>li rd, imm</code>（仅低 12 位有效）</td><td><code>addi rd, x0, imm</code></td><td></td></tr><tr><td><code>li</code></td><td><code>li rd, imm</code>（仅高 32 位有效）</td><td><code>lui rd, imm_hi</code> + <code>addi rd, rd, imm_lo</code></td><td>需要 2 条指令</td></tr><tr><td><code>li</code></td><td><code>li rd, imm</code>（任意 64 位值）</td><td>最多 <code>lui</code> + <code>addi</code> + <code>slli</code> + <code>addi</code> + ...</td><td>汇编器计算最优分解</td></tr></tbody></table><hr><h2 id="地址加载" tabindex="-1">地址加载 <a class="header-anchor" href="#地址加载" aria-label="Permalink to “地址加载”">​</a></h2><table tabindex="0"><thead><tr><th>伪指令</th><th>语法</th><th>展开为</th><th>说明</th></tr></thead><tbody><tr><td><code>la</code></td><td><code>la rd, symbol</code></td><td><code>auipc rd, %pcrel_hi(symbol)</code>; <code>addi rd, rd, %pcrel_lo(label)</code></td><td>加载符号的绝对地址（PC 相对寻址）</td></tr><tr><td><code>lla</code></td><td><code>lla rd, symbol</code></td><td><code>auipc rd, %pcrel_hi(symbol)</code>; <code>addi rd, rd, %pcrel_lo(label)</code></td><td>加载局部符号地址（同 la）</td></tr><tr><td><code>lga</code></td><td><code>lga rd, symbol</code></td><td><code>auipc rd, %got_pcrel_hi(symbol)</code>; <code>ld rd, %got_pcrel_lo(label)(rd)</code></td><td>通过 GOT 加载全局符号地址（位置无关代码）</td></tr><tr><td><code>lar</code></td><td><code>lar rd, symbol</code></td><td><code>auipc rd, %pcrel_hi(symbol)</code>; <code>addi rd, rd, %pcrel_lo(label)</code></td><td>加载只读符号地址</td></tr></tbody></table><hr><h2 id="函数调用与跳转" tabindex="-1">函数调用与跳转 <a class="header-anchor" href="#函数调用与跳转" aria-label="Permalink to “函数调用与跳转”">​</a></h2><table tabindex="0"><thead><tr><th>伪指令</th><th>语法</th><th>展开为</th><th>说明</th></tr></thead><tbody><tr><td><code>call</code></td><td><code>call symbol</code></td><td><code>auipc ra, %pcrel_hi(symbol)</code>; <code>jalr ra, %pcrel_lo(label)(ra)</code></td><td>函数调用（返回地址存 ra）</td></tr><tr><td><code>tail</code></td><td><code>tail symbol</code></td><td><code>auipc t1, %pcrel_hi(symbol)</code>; <code>jalr x0, %pcrel_lo(label)(t1)</code></td><td>尾调用优化（不保存返回地址）</td></tr><tr><td><code>ret</code></td><td><code>ret</code></td><td><code>jalr x0, ra, 0</code></td><td>函数返回（跳转至 ra）</td></tr><tr><td><code>j</code></td><td><code>j label</code></td><td><code>jal x0, label</code></td><td>无条件跳转</td></tr><tr><td><code>jr</code></td><td><code>jr rs</code></td><td><code>jalr x0, rs, 0</code></td><td>间接跳转（跳转至寄存器地址）</td></tr><tr><td><code>jal</code></td><td><code>jal label</code></td><td><code>jal x1, label</code></td><td>带链接跳转（保存返回地址至 ra）</td></tr></tbody></table><hr><h2 id="条件分支扩展" tabindex="-1">条件分支扩展 <a class="header-anchor" href="#条件分支扩展" aria-label="Permalink to “条件分支扩展”">​</a></h2><table tabindex="0"><thead><tr><th>伪指令</th><th>语法</th><th>展开为</th><th>说明</th></tr></thead><tbody><tr><td><code>beqz</code></td><td><code>beqz rs, label</code></td><td><code>beq rs, x0, label</code></td><td>rs == 0 则跳转</td></tr><tr><td><code>bnez</code></td><td><code>bnez rs, label</code></td><td><code>bne rs, x0, label</code></td><td>rs != 0 则跳转</td></tr><tr><td><code>blez</code></td><td><code>blez rs, label</code></td><td><code>bge x0, rs, label</code></td><td>rs &lt;= 0 则跳转（有符号）</td></tr><tr><td><code>bgez</code></td><td><code>bgez rs, label</code></td><td><code>bge rs, x0, label</code></td><td>rs &gt;= 0 则跳转（有符号）</td></tr><tr><td><code>bltz</code></td><td><code>bltz rs, label</code></td><td><code>blt rs, x0, label</code></td><td>rs &lt; 0 则跳转（有符号）</td></tr><tr><td><code>bgtz</code></td><td><code>bgtz rs, label</code></td><td><code>blt x0, rs, label</code></td><td>rs &gt; 0 则跳转（有符号）</td></tr><tr><td><code>bgt</code></td><td><code>bgt rs1, rs2, label</code></td><td><code>blt rs2, rs1, label</code></td><td>rs1 &gt; rs2 则跳转（有符号）</td></tr><tr><td><code>ble</code></td><td><code>ble rs1, rs2, label</code></td><td><code>bge rs2, rs1, label</code></td><td>rs1 &lt;= rs2 则跳转（有符号）</td></tr><tr><td><code>bgtu</code></td><td><code>bgtu rs1, rs2, label</code></td><td><code>bltu rs2, rs1, label</code></td><td>rs1 &gt; rs2 则跳转（无符号）</td></tr><tr><td><code>bleu</code></td><td><code>bleu rs1, rs2, label</code></td><td><code>bgeu rs2, rs1, label</code></td><td>rs1 &lt;= rs2 则跳转（无符号）</td></tr></tbody></table><hr><h2 id="csr-操作" tabindex="-1">CSR 操作 <a class="header-anchor" href="#csr-操作" aria-label="Permalink to “CSR 操作”">​</a></h2><table tabindex="0"><thead><tr><th>伪指令</th><th>语法</th><th>展开为</th><th>说明</th></tr></thead><tbody><tr><td><code>csrr</code></td><td><code>csrr rd, csr</code></td><td><code>csrrs rd, csr, x0</code></td><td>读 CSR（rs1=x0，无写入）</td></tr><tr><td><code>csrw</code></td><td><code>csrw csr, rs</code></td><td><code>csrrw x0, csr, rs</code></td><td>写 CSR（rd=x0，丢弃旧值）</td></tr><tr><td><code>csrs</code></td><td><code>csrs csr, rs</code></td><td><code>csrrs x0, csr, rs</code></td><td>置位 CSR（rd=x0，丢弃旧值）</td></tr><tr><td><code>csrc</code></td><td><code>csrc csr, rs</code></td><td><code>csrrc x0, csr, rs</code></td><td>清除 CSR（rd=x0，丢弃旧值）</td></tr><tr><td><code>csrwi</code></td><td><code>csrwi csr, uimm</code></td><td><code>csrrwi x0, csr, uimm</code></td><td>立即数写 CSR（uimm[4:0]）</td></tr><tr><td><code>csrsi</code></td><td><code>csrsi csr, uimm</code></td><td><code>csrrsi x0, csr, uimm</code></td><td>立即数置位 CSR</td></tr><tr><td><code>csrci</code></td><td><code>csrci csr, uimm</code></td><td><code>csrrci x0, csr, uimm</code></td><td>立即数清除 CSR</td></tr></tbody></table><hr><h2 id="空操作" tabindex="-1">空操作 <a class="header-anchor" href="#空操作" aria-label="Permalink to “空操作”">​</a></h2><table tabindex="0"><thead><tr><th>伪指令</th><th>语法</th><th>展开为</th><th>说明</th></tr></thead><tbody><tr><td><code>nop</code></td><td><code>nop</code></td><td><code>addi x0, x0, 0</code></td><td>空操作（不改变任何状态）</td></tr></tbody></table><hr><h2 id="浮点伪指令" tabindex="-1">浮点伪指令 <a class="header-anchor" href="#浮点伪指令" aria-label="Permalink to “浮点伪指令”">​</a></h2><table tabindex="0"><thead><tr><th>伪指令</th><th>语法</th><th>展开为</th><th>说明</th></tr></thead><tbody><tr><td><code>flw</code></td><td><code>flw fd, symbol</code></td><td><code>auipc xN, %pcrel_hi(symbol)</code>; <code>flw fd, %pcrel_lo(label)(xN)</code></td><td>从符号地址加载单精度浮点</td></tr><tr><td><code>fld</code></td><td><code>fld fd, symbol</code></td><td><code>auipc xN, %pcrel_hi(symbol)</code>; <code>fld fd, %pcrel_lo(label)(xN)</code></td><td>从符号地址加载双精度浮点</td></tr><tr><td><code>fsw</code></td><td><code>fsw fs, symbol, rt</code></td><td><code>auipc rt, %pcrel_hi(symbol)</code>; <code>fsw fs, %pcrel_lo(label)(rt)</code></td><td>存储单精度浮点至符号地址</td></tr><tr><td><code>fsd</code></td><td><code>fsd fs, symbol, rt</code></td><td><code>auipc rt, %pcrel_hi(symbol)</code>; <code>fsd fs, %pcrel_lo(label)(rt)</code></td><td>存储双精度浮点至符号地址</td></tr><tr><td><code>fmv.s</code></td><td><code>fmv.s fd, fs</code></td><td><code>fsgnj.s fd, fs, fs</code></td><td>单精度浮点寄存器间移动</td></tr><tr><td><code>fabs.s</code></td><td><code>fabs.s fd, fs</code></td><td><code>fsgnjx.s fd, fs, fs</code></td><td>单精度浮点绝对值</td></tr><tr><td><code>fneg.s</code></td><td><code>fneg.s fd, fs</code></td><td><code>fsgnjn.s fd, fs, fs</code></td><td>单精度浮点取负</td></tr><tr><td><code>fmv.d</code></td><td><code>fmv.d fd, fs</code></td><td><code>fsgnj.d fd, fs, fs</code></td><td>双精度浮点寄存器间移动</td></tr><tr><td><code>fabs.d</code></td><td><code>fabs.d fd, fs</code></td><td><code>fsgnjx.d fd, fs, fs</code></td><td>双精度浮点绝对值</td></tr><tr><td><code>fneg.d</code></td><td><code>fneg.d fd, fs</code></td><td><code>fsgnjn.d fd, fs, fs</code></td><td>双精度浮点取负</td></tr></tbody></table><hr><h2 id="load-store-全局符号" tabindex="-1">Load/Store 全局符号 <a class="header-anchor" href="#load-store-全局符号" aria-label="Permalink to “Load/Store 全局符号”">​</a></h2><table tabindex="0"><thead><tr><th>伪指令</th><th>语法</th><th>展开为</th><th>说明</th></tr></thead><tbody><tr><td><code>lb</code></td><td><code>lb rd, symbol</code></td><td><code>auipc rd, %pcrel_hi(symbol)</code>; <code>lb rd, %pcrel_lo(label)(rd)</code></td><td>从符号地址加载字节</td></tr><tr><td><code>lh</code></td><td><code>lh rd, symbol</code></td><td><code>auipc rd, %pcrel_hi(symbol)</code>; <code>lh rd, %pcrel_lo(label)(rd)</code></td><td>从符号地址加载半字</td></tr><tr><td><code>lw</code></td><td><code>lw rd, symbol</code></td><td><code>auipc rd, %pcrel_hi(symbol)</code>; <code>lw rd, %pcrel_lo(label)(rd)</code></td><td>从符号地址加载字</td></tr><tr><td><code>ld</code></td><td><code>ld rd, symbol</code></td><td><code>auipc rd, %pcrel_hi(symbol)</code>; <code>ld rd, %pcrel_lo(label)(rd)</code></td><td>从符号地址加载双字</td></tr><tr><td><code>lbu</code></td><td><code>lbu rd, symbol</code></td><td><code>auipc rd, %pcrel_hi(symbol)</code>; <code>lbu rd, %pcrel_lo(label)(rd)</code></td><td>无符号字节加载</td></tr><tr><td><code>lhu</code></td><td><code>lhu rd, symbol</code></td><td><code>auipc rd, %pcrel_hi(symbol)</code>; <code>lhu rd, %pcrel_lo(label)(rd)</code></td><td>无符号半字加载</td></tr><tr><td><code>lwu</code></td><td><code>lwu rd, symbol</code></td><td><code>auipc rd, %pcrel_hi(symbol)</code>; <code>lwu rd, %pcrel_lo(label)(rd)</code></td><td>无符号字加载</td></tr><tr><td><code>sb</code></td><td><code>sb rs, symbol, rt</code></td><td><code>auipc rt, %pcrel_hi(symbol)</code>; <code>sb rs, %pcrel_lo(label)(rt)</code></td><td>存储字节至符号地址</td></tr><tr><td><code>sh</code></td><td><code>sh rs, symbol, rt</code></td><td><code>auipc rt, %pcrel_hi(symbol)</code>; <code>sh rs, %pcrel_lo(label)(rt)</code></td><td>存储半字至符号地址</td></tr><tr><td><code>sw</code></td><td><code>sw rs, symbol, rt</code></td><td><code>auipc rt, %pcrel_hi(symbol)</code>; <code>sw rs, %pcrel_lo(label)(rt)</code></td><td>存储字至符号地址</td></tr><tr><td><code>sd</code></td><td><code>sd rs, symbol, rt</code></td><td><code>auipc rt, %pcrel_hi(symbol)</code>; <code>sd rs, %pcrel_lo(label)(rt)</code></td><td>存储双字至符号地址</td></tr></tbody></table><hr><h2 id="数据定义伪指令" tabindex="-1">数据定义伪指令 <a class="header-anchor" href="#数据定义伪指令" aria-label="Permalink to “数据定义伪指令”">​</a></h2><table tabindex="0"><thead><tr><th>伪指令</th><th>语法</th><th>说明</th></tr></thead><tbody><tr><td><code>.section .text</code></td><td>切换至代码段</td><td>后续指令放入 .text</td></tr><tr><td><code>.section .data</code></td><td>切换至数据段</td><td>后续数据放入 .data</td></tr><tr><td><code>.section .rodata</code></td><td>切换至只读数据段</td><td></td></tr><tr><td><code>.section .bss</code></td><td>切换至未初始化数据段</td><td></td></tr><tr><td><code>.globl symbol</code></td><td>声明全局符号</td><td>其他文件可引用</td></tr><tr><td><code>.local symbol</code></td><td>声明本地符号</td><td>仅本文件可见</td></tr><tr><td><code>.align n</code></td><td>对齐至 2^n 字节边界</td><td>填充 nop / 零</td></tr><tr><td><code>.balign n, fill</code></td><td>对齐至 n 字节，填充 fill</td><td></td></tr><tr><td><code>.zero n</code></td><td>预留 n 字节零</td><td></td></tr><tr><td><code>.byte expr</code></td><td>定义 1 字节</td><td></td></tr><tr><td><code>.2byte expr</code> / <code>.half</code></td><td>定义 2 字节</td><td></td></tr><tr><td><code>.4byte expr</code> / <code>.word</code></td><td>定义 4 字节</td><td></td></tr><tr><td><code>.8byte expr</code> / <code>.dword</code></td><td>定义 8 字节</td><td></td></tr><tr><td><code>.float value</code></td><td>定义 4 字节 IEEE 754 单精度</td><td></td></tr><tr><td><code>.double value</code></td><td>定义 8 字节 IEEE 754 双精度</td><td></td></tr><tr><td><code>.ascii &quot;string&quot;</code></td><td>嵌入 ASCII 字符串（无 \\0）</td><td></td></tr><tr><td><code>.asciz &quot;string&quot;</code> / <code>.string</code></td><td>嵌入 ASCII 字符串（带 \\0）</td><td></td></tr><tr><td><code>.skip n</code></td><td>跳过 n 字节</td><td></td></tr><tr><td><code>.size symbol, expr</code></td><td>设置符号大小</td><td>ELF 调试信息</td></tr><tr><td><code>.type symbol, @function</code></td><td>标记符号类型</td><td>ELF 符号表</td></tr></tbody></table><hr><h2 id="汇编控制伪指令" tabindex="-1">汇编控制伪指令 <a class="header-anchor" href="#汇编控制伪指令" aria-label="Permalink to “汇编控制伪指令”">​</a></h2><table tabindex="0"><thead><tr><th>伪指令</th><th>语法</th><th>说明</th></tr></thead><tbody><tr><td><code>.equ name, value</code></td><td>定义常量</td><td>不可重定义</td></tr><tr><td><code>.set name, value</code></td><td>定义可重定义常量</td><td></td></tr><tr><td><code>.macro name args</code> ... <code>.endm</code></td><td>定义宏</td><td>参数复用</td></tr><tr><td><code>.include &quot;file.s&quot;</code></td><td>包含其他汇编文件</td><td></td></tr><tr><td><code>.text</code></td><td>切换至 .text 段</td><td>简写</td></tr><tr><td><code>.data</code></td><td>切换至 .data 段</td><td>简写</td></tr><tr><td><code>.rodata</code></td><td>切换至 .rodata 段</td><td>简写</td></tr><tr><td><code>.bss</code></td><td>切换至 .bss 段</td><td>简写</td></tr><tr><td><code>.end</code></td><td>汇编结束标记</td><td></td></tr></tbody></table><hr><h2 id="调用约定快捷伪指令" tabindex="-1">调用约定快捷伪指令 <a class="header-anchor" href="#调用约定快捷伪指令" aria-label="Permalink to “调用约定快捷伪指令”">​</a></h2><table tabindex="0"><thead><tr><th>伪指令</th><th>语法</th><th>等价操作</th><th>说明</th></tr></thead><tbody><tr><td><code>push {regs}</code></td><td>汇编器展开</td><td><code>addi sp, sp, -N; sd reg, offset(sp)</code></td><td>入栈（RISC-V 无原生 push，由汇编器生成）</td></tr><tr><td><code>pop {regs}</code></td><td>汇编器展开</td><td><code>ld reg, offset(sp); addi sp, sp, N</code></td><td>出栈</td></tr></tbody></table><blockquote><p><strong>注意</strong>：RISC-V 没有原生 push/pop 指令，但 GNU 汇编器和部分工具链提供 <code>push</code>/<code>pop</code> 宏作为便利。</p></blockquote><hr><h2 id="伪指令数量统计" tabindex="-1">伪指令数量统计 <a class="header-anchor" href="#伪指令数量统计" aria-label="Permalink to “伪指令数量统计”">​</a></h2><table tabindex="0"><thead><tr><th>类别</th><th>数量</th></tr></thead><tbody><tr><td>寄存器间移动</td><td>9</td></tr><tr><td>立即数/地址加载</td><td>4</td></tr><tr><td>函数调用/跳转</td><td>6</td></tr><tr><td>条件分支扩展</td><td>10</td></tr><tr><td>CSR 操作</td><td>7</td></tr><tr><td>空操作</td><td>1</td></tr><tr><td>浮点运算</td><td>10</td></tr><tr><td>Load/Store 全局符号</td><td>14</td></tr><tr><td>数据定义</td><td>18</td></tr><tr><td>汇编控制</td><td>9</td></tr><tr><td><strong>合计</strong></td><td><strong>88</strong></td></tr></tbody></table>',41))])}]]);export{a as __pageData,b as default};
